// Parse the topic from Claude's response
const response = $input.first().json.response || $input.first().json.text || $input.first().json.message?.content?.[0]?.text || JSON.stringify($input.first().json);
let topic;
try {
  const jsonMatch = response.match(/\{[^}]+\}/);
  topic = JSON.parse(jsonMatch[0]);
} catch(e) {
  topic = { topic_number: 1, title: 'Warum Handwerker 30% mehr Auftraege verlieren ohne Telefonassistenz', slug: 'handwerker-verpasste-anrufe', category: 'Branche', excerpt: 'Verpasste Anrufe kosten Handwerksbetriebe Tausende Euro im Jahr.' };
}

const today = new Date();
const months = ['Januar','Februar','Maerz','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];
const dateStr = today.getDate() + '. ' + months[today.getMonth()] + ' ' + today.getFullYear();
const isoDate = today.toISOString().split('T')[0];

return [{ json: { ...topic, dateStr, isoDate } }];

