// Prepare the article HTML for GitHub API
const articleHtml = $input.first().json.response || $input.first().json.text || $input.first().json.message?.content?.[0]?.text || '';
const slug = $('Thema parsen').first().json.slug;
const title = $('Thema parsen').first().json.title;
const category = $('Thema parsen').first().json.category;
const dateStr = $('Thema parsen').first().json.dateStr;
const isoDate = $('Thema parsen').first().json.isoDate;
const excerpt = $('Thema parsen').first().json.excerpt;

// Base64 encode for GitHub API
const articleBase64 = Buffer.from(articleHtml, 'utf-8').toString('base64');

// Choose a fitting image based on category/topic
const images = ['nora-buero.png','nora-handwerk-neu.png','nora-zahnarzt.png','nora-architekt.png','nora-friseur.png','nora-physiotherapie.png','nora-elektro.png','nora-stehend.png'];
const imgIndex = Math.floor(Math.random() * images.length);
const cardImage = images[imgIndex];

// Build the new blog card HTML
const newCard = `
        <a href="./` + slug + `/" class="blog-card reveal">
          <div class="blog-card-img">
            <img src="../images/` + cardImage + `" alt="` + title + `">
          </div>
          <div class="blog-card-body">
            <div class="blog-card-meta">
              <span class="blog-card-category">` + category + `</span>
              <span class="blog-card-date">` + dateStr + `</span>
            </div>
            <h2 class="blog-card-title">` + title + `</h2>
            <p class="blog-card-excerpt">` + excerpt + `</p>
            <span class="blog-card-link">Weiterlesen &rarr;</span>
          </div>
        </a>`;

// Build new BlogPosting schema entry
const newSchemaEntry = `      {
        "@type": "BlogPosting",
        "headline": "` + title + `",
        "datePublished": "` + isoDate + `",
        "description": "` + excerpt + `",
        "url": "https://fonora.ai/blog/` + slug + `/",
        "author": {
          "@type": "Person",
          "name": "Olga Reyes-Busch"
        }
      }`;

// New sitemap entry
const sitemapEntry = `  <url>\n    <loc>https://fonora.ai/blog/` + slug + `/</loc>\n    <changefreq>monthly</changefreq>\n    <priority>0.7</priority>\n  </url>`;

return [{ json: { slug, title, articleBase64, newCard, newSchemaEntry, sitemapEntry } }];

const blogData = $input.first().json;
const sha = blogData.sha;
const content = Buffer.from(blogData.content, 'base64').toString('utf-8');
const newCard = $('Dateien vorbereiten').first().json.newCard;
const newSchema = $('Dateien vorbereiten').first().json.newSchemaEntry;

// Insert new card after <div class="blog-grid">
let updated = content.replace(
  '<div class="blog-grid">',
  '<div class="blog-grid">' + newCard
);

// Insert new schema entry in blogPost array
updated = updated.replace(
  '"blogPost": [',
  '"blogPost": [\n' + newSchema + ','
);

const updatedBase64 = Buffer.from(updated, 'utf-8').toString('base64');

return [{ json: { sha, updatedBase64 } }];

const sitemapData = $input.first().json;
const sha = sitemapData.sha;
const content = Buffer.from(sitemapData.content, 'base64').toString('utf-8');
const newEntry = $('Dateien vorbereiten').first().json.sitemapEntry;

// Insert before </urlset>
const updated = content.replace('</urlset>', newEntry + '\n</urlset>');
const updatedBase64 = Buffer.from(updated, 'utf-8').toString('base64');

return [{ json: { sha, updatedBase64 } }];
